import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import App from './App';
import reportWebVitals from './reportWebVitals';

const multer = require('multer');
const path = require('path');

// 1. Servir la carpeta para que el navegador pueda ver las fotos
app.use('/uploads', express.static(path.join(__dirname, 'uploads')));

// 2. Configurar dónde y cómo se guardan los nombres
const storage = multer.diskStorage({
  destination: (req, file, cb) => { cb(null, 'uploads/'); },
  filename: (req, file, cb) => { cb(null, Date.now() + path.extname(file.originalname)); }
});
const upload = multer({ storage });

// 3. Ruta de guardado corregida para recibir el archivo
app.post('/api/productos', upload.single('imagen'), (req, res) => {
  const { nombre, stock, precio_venta } = req.body;
  const imagen = req.file ? req.file.filename : null; // Guardamos solo el nombre del archivo

  const sql = 'INSERT INTO productos (nombre, imagen, stock, precio_venta, categoria) VALUES (?, ?, ?, ?, "General")';
  db.query(sql, [nombre, imagen, stock, precio_venta], (err) => {
    if (err) return res.status(500).send(err);
    res.json({ success: true });
  });
});
const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

// If you want to start measuring performance in your app, pass a function
// to log results (for example: reportWebVitals(console.log))
// or send to an analytics endpoint. Learn more: https://bit.ly/CRA-vitals
reportWebVitals();
